function ModelRune:InitRunePos()
    self._runePosList = {}
    for k, v in pairs(GameTable.MagicRunePosRef) do
        local funcType = v.type
        local funcList = self._runePosList[funcType]
        if not funcList then
            funcList = {}
            self._runePosList[funcType] = funcList
        end

        local unlock = v.unlock

        --解析修改
        unlock = string.split(unlock, ",")
        local unlockType, demand = {}, {}
        for k, unlockInfo in ipairs(unlock) do
            local tempUnlock = string.split(unlockInfo, "=")


            table.insert(unlockType, tonumber(tempUnlock[1]))
            table.insert(demand, tonumber(tempUnlock[2]))
        end

        table.insert(funcList, { unlockType = unlockType, demand = demand, pos = v.pos })
    end
    for i, v in ipairs(self._runePosList) do
        table.sort(v, function(v1, v2)
            return v1.pos < v2.pos
        end)
    end
end

function ModelRune:InitRuneAttrRef()
    local attrGroupList = {}
    local attrRefIdList = {}
    local ref = GameTable.MagicRuneAttrRef
    for k, v in pairs(ref) do
        local attrRefIdInfo = {}
        attrRefIdList[k] = attrRefIdInfo

        local attrGroupId = v.attrGroupId
        local attrGroupInfo = attrGroupList[attrGroupId]
        if not attrGroupInfo then
            attrGroupInfo = {}
            attrGroupList[attrGroupId] = attrGroupInfo
        end
        local attrList = {}
        local attr = string.split(v.attr, ",")
        for idx, val in ipairs(attr) do
            val = string.split(val, "=")
            local attrRefId, attrType, attrVal = tonumber(val[1]), tonumber(val[2]), tonumber(val[3])
            table.insert(attrList, {
                attrType = attrType,
                attrRefId = attrRefId,
                attrVal = attrVal,
            })
        end
        attrRefIdInfo.attr = attrList
        attrRefIdInfo.attrGroupId = attrGroupId

        table.insert(attrGroupInfo, {
            refId = k,
            attr = attrList,
            attrGroupId = attrGroupId,
        })
    end
    for attrGroupId, info in pairs(attrGroupList) do
        table.sort(info, function(a, b)
            return a.refId < b.refId
        end)
    end
    self._attrGroupList = attrGroupList
    self._attrRefIdList = attrRefIdList
end

function ModelRune:InitRuneSkillRef()
    local runeUpItemList = {}
    local runeSkillList = {}
    local qualityRuneSkillList = {}
    for k, v in pairs(GameTable.MagicRuneSkillRef) do
        local upItem = string.split(v.upItem, ",")
        for idx, val in ipairs(upItem) do
            val = string.split(val, "=")

            local itemRefId = tonumber(val[2])
            local runeUpItemInfo = runeUpItemList[itemRefId]
            if not runeUpItemInfo then
                runeUpItemInfo = {}
                runeUpItemList[itemRefId] = runeUpItemInfo
            end
            runeUpItemInfo[k] = k
        end

        local skillType = v.skillType
        local skillTypeList = runeSkillList[skillType]
        if not skillTypeList then
            skillTypeList = {}
            runeSkillList[skillType] = skillTypeList
        end
        table.insert(skillTypeList, {
            refId = v.refId,
            skillId = v.SkillId,
            nextId = v.nextId,
            skillLevel = v.skillLevel,
            sort = v.sort,
        })

        local quality = v.quality
        local qualityRuneSkillInfo = qualityRuneSkillList[quality]
        if not qualityRuneSkillInfo then
            qualityRuneSkillInfo = {}
            qualityRuneSkillList[quality] = qualityRuneSkillInfo
        end
        table.insert(qualityRuneSkillInfo, {
            refId = k,
            skillRefId = v.SkillId,
            skillType = skillType,
            skillLevel = v.skillLevel,
            sort = v.sort,
            quality = quality,
        })
    end
    for k, v in pairs(runeSkillList) do
        table.sort(v, function(a, b)
            return a.sort < b.sort
        end)
    end

    for k, v in pairs(qualityRuneSkillList) do
        table.sort(v, function(a, b)
            return a.sort < b.sort
        end)
    end

    self._runeSkillList = runeSkillList
    self._runeUpItemList = runeUpItemList
    self._qualityRuneSkillList = qualityRuneSkillList
end

