function ModelRune:InitRuneQuenchingRef()
    local initRuneQuenchingRef = {}                  -- key:needClass,valList:有序的列表
    local initRuneQuenchingRefNeedClassAndLevel = {} -- key:needClass and level,val:表格
    local initRuneQuenchingRefKey = {}               -- key:refId,val:表格
    local initRuneLevelList = {}
    local ref = {}--GameTable.RuneQuenchingRef
    for k, v in pairs(ref) do
        local needClass = v.needClass
        local level = v.level
        local needClassInfoList = initRuneQuenchingRef[needClass]
        if not needClassInfoList then
            needClassInfoList = {}
            initRuneQuenchingRef[needClass] = needClassInfoList
        end

        if not initRuneLevelList[needClass] then
            initRuneLevelList[needClass] = level
        elseif initRuneLevelList[needClass] < level then
            initRuneLevelList[needClass] = level
        end

        local needClassInfo = {}
        needClassInfo.refId = k
        needClassInfo.level = level
        needClassInfo.needClass = v.needClass
        needClassInfo.nextLevel = v.nextLevel
        local attrList = {}
        local attr = string.split(v.attr, ",")
        for idx, val in ipairs(attr) do
            val = string.split(val, "=")
            table.insert(attrList, {
                attrRefId = tonumber(val[1]),
                attrType = tonumber(val[2]),
                attrVal = tonumber(val[3]),
            })
        end
        needClassInfo.attr = attrList

        local upItemList = {}
        local upItem = string.split(v.upItem, ",")
        for idx, val in ipairs(upItem) do
            val = string.split(val, "=")
            table.insert(upItemList, {
                itemType = tonumber(val[1]),
                itemId = tonumber(val[2]),
                itemNum = tonumber(val[3]),
            })
        end
        needClassInfo.upItem = upItemList

        local returnUpItemList = {}
        local returnUpItem = string.split(v.returnUpItem, ",")
        for idx, val in ipairs(returnUpItem) do
            val = string.split(val, "=")
            table.insert(returnUpItemList, {
                itemType = tonumber(val[1]),
                itemId = tonumber(val[2]),
                itemNum = tonumber(val[3]),
            })
        end
        needClassInfo.returnUpItem = returnUpItemList

        local initRuneQuenchingRefNeedClassAndLevelList = initRuneQuenchingRefNeedClassAndLevel[needClass]
        if not initRuneQuenchingRefNeedClassAndLevelList then
            initRuneQuenchingRefNeedClassAndLevelList = {}
            initRuneQuenchingRefNeedClassAndLevel[needClass] = initRuneQuenchingRefNeedClassAndLevelList
        end
        initRuneQuenchingRefNeedClassAndLevelList[level] = needClassInfo
        initRuneQuenchingRefKey[k] = needClassInfo
        table.insert(needClassInfoList, needClassInfo)
    end

    for needClass, needClassInfoList in pairs(initRuneQuenchingRef) do
        table.sort(needClassInfoList, function(a, b)
            return a.level < b.level
        end)
    end
    self._initRuneQuenchingRef = initRuneQuenchingRef
    self._initRuneQuenchingRefKey = initRuneQuenchingRefKey
    self._initRuneQuenchingRefNeedClassAndLevel = initRuneQuenchingRefNeedClassAndLevel
    self._initRuneLevelList = initRuneLevelList
end

function ModelRune:InitRuneQuenchingClassRef()
    local initRuneQuenchingClassRef = {}
    local initRuneQuenchingClassRefKey = {}
    local addAttrList = {}
    local ref = GameTable.MagicRuneQuenchingClassRef
    for k, v in pairs(ref) do
        local initRuneQuenchingClassList = {}

        local runeClass = v.runeClass
        initRuneQuenchingClassList.refId = k
        initRuneQuenchingClassList.runeClass = v.runeClass
        initRuneQuenchingClassList.nextClass = v.nextClass
        initRuneQuenchingClassList.desc = v.desc
        initRuneQuenchingClassList.upQuality = v.upQuality
        initRuneQuenchingClassList.needQuality = v.needQuality

        local effectTypeList = {}
        local effectType = string.split(v.effectType, ",")
        for idx, val in ipairs(effectType) do
            val = string.split(val, "=")
            table.insert(effectTypeList, {
                addType = tonumber(val[1]),
                addInfo = tonumber(val[2]),
            })
        end
        initRuneQuenchingClassList.effectType = v.effectTypeList

        local attrList = {}
        local attr = string.split(v.attr, ",")
        for idx, val in ipairs(attr) do
            val = string.split(val, "=")
            table.insert(attrList, {
                attrRefId = tonumber(val[1]),
                attrType = tonumber(val[2]),
                attrVal = tonumber(val[3]),
            })
        end
        initRuneQuenchingClassList.attr = attrList

        local upItemList = {}
        local upItem = string.split(v.upItem, ",")
        for idx, val in ipairs(upItem) do
            val = string.split(val, "=")
            table.insert(upItemList, {
                itemType = tonumber(val[1]),
                itemId = tonumber(val[2]),
                itemNum = tonumber(val[3]),
            })
        end
        initRuneQuenchingClassList.upItem = upItemList

        local freeUpItemList = {}
        local freeUpItem = string.split(v.freeUpItem, ",")
        for idx, val in ipairs(freeUpItem) do
            val = string.split(val, "=")
            local needRuneRefId = tonumber(val[1])
            local needNum = tonumber(val[2])
            table.insert(freeUpItemList, {
                itemType = LItemTypeConst.TYPE_RUNE,
                itemId = needRuneRefId,
                itemNum = needNum,
                needRuneRefId = needRuneRefId,
                needNum = needNum,
            })
        end
        initRuneQuenchingClassList.freeUpItem = freeUpItemList

        initRuneQuenchingClassRef[runeClass] = initRuneQuenchingClassList
        initRuneQuenchingClassRefKey[k] = initRuneQuenchingClassList

        table.insert(addAttrList, {
            attrList = attrList,
            runeClass = runeClass,
            refId = k,
        })
    end
    self._initRuneQuenchingClassRef = initRuneQuenchingClassRef
    self._initRuneQuenchingClassRefKey = initRuneQuenchingClassRefKey

    table.sort(addAttrList, function(a, b)
        return a.runeClass > b.runeClass
    end)

    local allAttrAddList = {}
    for i, v in ipairs(addAttrList) do
        local tAddAttrList = {}
        if i == #addAttrList then
            for idx, val in ipairs(v.attrList) do
                local attrRefId, attrType, attrVal = val.attrRefId, val.attrType, val.attrVal
                local attrRefIdList = tAddAttrList[attrRefId]
                if not attrRefIdList then
                    attrRefIdList = {}
                    tAddAttrList[attrRefId] = attrRefIdList
                end
                local attrTypeNum = attrRefIdList[attrType] or 0
                attrRefIdList[attrType] = attrVal + attrTypeNum
            end
        else
            for _i, _v in ipairs(addAttrList) do
                if v.runeClass >= _v.runeClass then
                    local attr = _v.attrList
                    for idx, val in ipairs(attr) do
                        local attrRefId, attrType, attrVal = val.attrRefId, val.attrType, val.attrVal
                        local attrRefIdList = tAddAttrList[attrRefId]
                        if not attrRefIdList then
                            attrRefIdList = {}
                            tAddAttrList[attrRefId] = attrRefIdList
                        end
                        local attrTypeNum = attrRefIdList[attrType] or 0
                        attrRefIdList[attrType] = attrVal + attrTypeNum
                    end
                end
            end
        end
        local t = {}
        for attrRefId, attrTypeList in pairs(tAddAttrList) do
            for attrType, attrNum in pairs(attrTypeList) do
                table.insert(t, {
                    attrRefId = attrRefId,
                    attrType = attrType,
                    attrVal = attrNum,
                })
            end
        end
        allAttrAddList[v.refId] = t
    end
    self._allAttrAddList = allAttrAddList
end

function ModelRune:InitRuneComposeRef()
    local initRuneComposeRefList = {}
    local initRuneComposeRefKeyList = {}
    local runeCanComposeList = {}
    local ref = GameTable.MagicRuneComposeRef
    for k, v in pairs(ref) do
        local needRune = v.needRune
        local needRuneList = initRuneComposeRefList[needRune]
        if not needRuneList then
            needRuneList = {}
            initRuneComposeRefList[needRune] = needRuneList
        end

        if not runeCanComposeList[needRune] then
            runeCanComposeList[needRune] = true
        end

        local number = v.number
        local splitInfo = {}
        needRuneList[number] = splitInfo

        splitInfo.needRune = needRune
        splitInfo.number = number
        splitInfo.needLevel = v.needLevel
        splitInfo.rate = v.rate
        splitInfo.get = v.get

        local composeNeedGlod = string.split(v.composeNeedGlod, "=")
        splitInfo.composeNeedGlod = {
            itemType = tonumber(composeNeedGlod[1]),
            itemId = tonumber(composeNeedGlod[2]),
            itemNum = tonumber(composeNeedGlod[3]),
        }
        local showGet = string.split(v.showGet, "=")
        splitInfo.showGet = {
            itemType = tonumber(showGet[1]),
            itemId = tonumber(showGet[2]),
            itemNum = tonumber(showGet[3]),
        }
        local failRewardList = {}
        local failReward = string.split(v.failReward, ",")
        for idx, val in ipairs(failReward) do
            val = string.split(val, "=")
            table.insert(failRewardList, {
                itemType = tonumber(val[1]),
                itemId = tonumber(val[2]),
                itemNum = tonumber(val[3]),
            })
        end
        splitInfo.failReward = failRewardList

        initRuneComposeRefKeyList[k] = splitInfo
    end
    self._initRuneComposeRefList = initRuneComposeRefList
    self._initRuneComposeRefKeyList = initRuneComposeRefKeyList
    self._runeCanComposeList = runeCanComposeList
end

