function ModelRune:IsMaxClass(runeData)
    if not runeData then
        return false
    end
    local refId = runeData.refId
    local isQuenching = self:IsCanQuenchingByRefId(refId)
    if not isQuenching then
        return true
    end

    if self:IsMaxQuenching(runeData.clazzRefId) then
        return true
    end
    return false
end

-- upType == 1:升级，2：升阶
function ModelRune:GetRuneUpStarAndUpLevelList(runeData, upType)
    local list = {}
    if runeData then
        local refId = runeData.refId
        local isQuenching = self:IsCanQuenchingByRefId(refId)
        local isMaxClass = self:IsMaxClass(runeData)
        local levelRefId = runeData.levelRefId
        local clazzRefId = runeData.clazzRefId
        local curLevelRef = self:GetRuneQuenchingRefByRefId(levelRefId)
        local curClassRef = self:GetInitRuneQuenchingClassRefByRefId(clazzRefId)
        if curLevelRef and curClassRef then
            local curStar = self:GetShowStarByRefId(refId) or 1
            local curLv = curLevelRef.level
            if isQuenching then
                if upType == 1 then
                    local nextStar = isMaxClass and -1 or curStar
                    table.insert(list, {
                        showStatus = 1,
                        curStarNum = curStar,
                        nextStarNum = nextStar,
                    })
                    local nextLevel = curLevelRef.nextLevel
                    local nextLevelRef = self:GetRuneQuenchingRefByRefId(nextLevel)
                    local nextLv = not isMaxClass and nextLevelRef and nextLevelRef.level or 0
                    table.insert(list, {
                        showStatus = 2,
                        curLevelNum = curLv,
                        nextLevelNum = nextLv,
                    })
                elseif upType == 2 then
                    local upQuality = curClassRef.upQuality
                    local nextStar = isMaxClass and -1 or self:GetShowStarByRefId(upQuality)
                    table.insert(list, {
                        showStatus = 1,
                        curStarNum = curStar,
                        nextStarNum = nextStar,
                    })
                    local nextLv = not isMaxClass and curLv or 0
                    table.insert(list, {
                        showStatus = 2,
                        curLevelNum = curLv,
                        nextLevelNum = nextLv,
                    })
                end
            else
                table.insert(list, {
                    showStatus = 1,
                    curStarNum = curStar,
                    nextStarNum = 0,
                })
                table.insert(list, {
                    showStatus = 2,
                    curLevelNum = curLv,
                })
            end
        end
    end
    return list
end

function ModelRune:SortAttrList(list)
    list = list or {}
    table.sort(list, function(a, b)
        local attrRefIdA, attrRefIdB = a.attrRefId, b.attrRefId
        if attrRefIdA ~= attrRefIdB then
            local sortA, sortB = gModelHero:GetAttributeSortById(attrRefIdA), gModelHero:GetAttributeSortById(attrRefIdB)
            return sortA < sortB
        else
            return a.attrType < b.attrType
        end
    end)
    return list
end

function ModelRune:GetKeyValueAttrList(attrList)
    local list = {}
    attrList = attrList or {}
    for i, v in ipairs(attrList) do
        local attrRefId = v.attrRefId
        local attrType = v.attrType
        local attrRefIdList = list[attrRefId]
        if not attrRefIdList then
            attrRefIdList = {}
            list[attrRefId] = attrRefIdList
        end
        local curAttrNum = attrRefIdList[attrType] or 0
        attrRefIdList[attrType] = curAttrNum + v.attrVal
    end
    return list
end

-- 两个属性列表加起来总和    属性refId - 属性类型 - 总数
function ModelRune:FormatTwoAttrListToKeyValueList(list1, list2)
    local allAttrList = {}
    for attrRefId, attrTypeList in pairs(list1) do
        local allAttrRefIdList = allAttrList[attrRefId]
        if not allAttrRefIdList then
            allAttrRefIdList = {}
            allAttrList[attrRefId] = allAttrRefIdList
        end
        for attrType, attrVal in pairs(attrTypeList) do
            local allAttrTypeNum = allAttrRefIdList[attrType] or 0
            allAttrRefIdList[attrType] = allAttrTypeNum + attrVal
        end
    end
    for attrRefId, attrTypeList in pairs(list2) do
        local allAttrRefIdList = allAttrList[attrRefId]
        if not allAttrRefIdList then
            allAttrRefIdList = {}
            allAttrList[attrRefId] = allAttrRefIdList
        end
        for attrType, attrVal in pairs(attrTypeList) do
            local allAttrTypeNum = allAttrRefIdList[attrType] or 0
            allAttrRefIdList[attrType] = allAttrTypeNum + attrVal
        end
    end
    return allAttrList
end

-- 前后属性    属性refId - 属性类型 - 总数
function ModelRune:GetKeyValueTwoAttrList(curList, nextList, isAdd)
    local allAttrList = {}
    for attrRefId, attrTypeList in pairs(curList) do
        for attrType, attrNum in pairs(attrTypeList) do
            local attrRefIdList = allAttrList[attrRefId]
            if not attrRefIdList then
                attrRefIdList = {}
                allAttrList[attrRefId] = attrRefIdList
            end
            local bAttrTypeList = {
                beforeAttrVal = attrNum,
            }
            attrRefIdList[attrType] = bAttrTypeList
        end
    end
    for attrRefId, attrTypeList in pairs(nextList) do
        for attrType, attrNum in pairs(attrTypeList) do
            local attrRefIdList = allAttrList[attrRefId]
            if not attrRefIdList then
                attrRefIdList = {}
                allAttrList[attrRefId] = attrRefIdList
            end
            local beforeAttrVal = 0
            local tAttrTypeList = attrRefIdList[attrType]
            if tAttrTypeList then
                beforeAttrVal = tAttrTypeList.beforeAttrVal or 0
            end
            local ttAttrTypeList = {
                beforeAttrVal = beforeAttrVal,
                laterAttrVal = isAdd and attrNum + beforeAttrVal or attrNum
            }
            attrRefIdList[attrType] = ttAttrTypeList
        end
    end
    return allAttrList
end

-- 计算所有属性的前后数据
function ModelRune:GetAllAttrAddList(allAttrList, baseAttrList)
    local addUpClassList = {}
    baseAttrList = baseAttrList or {}
    for attrRefId, attrTypeList in pairs(allAttrList) do
        for attrType, attrNumList in pairs(attrTypeList) do
            local addUpClassRefIdList = addUpClassList[attrRefId]
            if not addUpClassRefIdList then
                addUpClassRefIdList = {}
                addUpClassList[attrRefId] = addUpClassRefIdList
            end
            local addUpClassTypeList = addUpClassRefIdList[attrType]
            if not addUpClassTypeList then
                addUpClassTypeList = {}
                addUpClassRefIdList[attrType] = addUpClassTypeList
            end
            local beforeAttrVal, laterAttrVal = attrNumList.beforeAttrVal or 0, attrNumList.laterAttrVal or 0
            local classAttrRefIdList = baseAttrList[attrRefId]
            if classAttrRefIdList then
                local classAttrNum = classAttrRefIdList[attrType]
                if classAttrNum then
                    beforeAttrVal, laterAttrVal = beforeAttrVal + classAttrNum, laterAttrVal + classAttrNum
                end
            end
            addUpClassTypeList.beforeAttrVal = beforeAttrVal
            addUpClassTypeList.laterAttrVal = laterAttrVal
        end
    end
    local list = {}
    for attrRefId, attrTypeList in pairs(addUpClassList) do
        for attrType, attrNumList in pairs(attrTypeList) do
            table.insert(list, {
                attrRefId = attrRefId,
                attrType = attrType,
                beforeAttrVal = attrNumList.beforeAttrVal or 0,
                laterAttrVal = attrNumList.laterAttrVal or 0,
                showStatus = 3
            })
        end
    end
    list = self:SortAttrList(list)
    return list
end

-- 获取当前升级属性列表
function ModelRune:GetCurLevelAttrList(runeData)
    local list = {}
    if runeData then
        --[[        local runeRefId = runeData.refId
                local isQuenching = self:IsCanQuenchingByRefId(runeRefId)
                if isQuenching then
                end]]
        local levelRefId = runeData.levelRefId
