    if runeData then
        --[[        local runeRefId = runeData.refId
                local isQuenching = self:IsCanQuenchingByRefId(runeRefId)
                if isQuenching then
                end]]
        local clazzRefId = runeData.clazzRefId
        local curClassRef = self:GetInitRuneQuenchingClassRefByRefId(clazzRefId)
        local attrList = curClassRef and curClassRef.attr or {}
