-- 获取升级属性列表，前后对比
function ModelRune:GetRuneUpLevelAttrList(runeData)
    local list = {}
    if runeData then
        local isMaxClass = self:IsMaxClass(runeData)
        local classAttrList = self:GetCurClassAttrList(runeData)
        local levelRefId = runeData.levelRefId
        local clazzRefId = runeData.clazzRefId
        local runeClass = self:GetRuneClassByClassRefId(clazzRefId)
        local curLevelRef = self:GetRuneQuenchingRefByRefId(levelRefId)
        local curAttrList = curLevelRef and curLevelRef.attr or {}
        local curLevelAttrList = self:GetKeyValueAttrList(curAttrList)
        local nextLevel = curLevelRef and curLevelRef.nextLevel
        local isNotEnd = nextLevel and nextLevel ~= -1
        local nextLevelRef
        if isNotEnd then
            nextLevelRef = self:GetRuneQuenchingRefByRefId(nextLevel)
        end
        local needClass = nextLevelRef and nextLevelRef.needClass
        local nextAttrList
        if needClass and runeClass < needClass then
            nextAttrList = {}
        else
            nextAttrList = nextLevelRef and nextLevelRef.attr or {}
        end
        local nextLevelAttrList = self:GetKeyValueAttrList(nextAttrList)
        local allAttrList = self:GetKeyValueTwoAttrList(curLevelAttrList, nextLevelAttrList)
        list = self:GetAllAttrAddList(allAttrList, classAttrList)
    end
    return list
end

-- 符文淬炼属性列表
function ModelRune:GetRuneUpAttrList(refIdList, isMaxQuenching)
    local RuneAttrRef = GameTable.MagicRuneAttrRef
    table.sort(refIdList, function(a, b)
        local refA = RuneAttrRef[a]
        local refB = RuneAttrRef[b]
        if refA.sort ~= refB.sort then
            return refA.sort < refB.sort
        end
        return refA.id < refB.id
    end)

    local attrList = {}

    for k, refId in ipairs(refIdList) do
        local ref = RuneAttrRef[refId]
        local nextRef = RuneAttrRef[ref.nextAttr]
        local v = string.split(ref.attr, "=")
        local attrId, type, value = tonumber(v[1]), tonumber(v[2]), tonumber(v[3])
        local tab = { attrRefId = attrId, attrType = type, beforeAttrVal = value, showStatus = 3}
        if nextRef and not isMaxQuenching then
            v = string.split(nextRef.attr, "=")
            value = tonumber(v[3])
            tab.laterAttrVal = value
        end
        attrList[k] = tab
    end

    return attrList
end

-- 获取升阶属性列表，前后对比
function ModelRune:GetRuneUpClassAttrList(runeData)
    local list = {}
    if runeData then
        local isMaxClass = self:IsMaxClass(runeData)
        local lvAttrList = self:GetCurLevelAttrList(runeData)
        local clazzRefId = runeData.clazzRefId
        local curClassRef = self:GetInitRuneQuenchingClassRefByRefId(clazzRefId)
        local curAttrList = curClassRef and curClassRef.attr or {}
        local curClassAttrList = self:GetKeyValueAttrList(curAttrList)
        local nextClass = curClassRef and curClassRef.nextClass
        local isNotEnd = nextClass and nextClass ~= -1
        local nextClassRef
        if isNotEnd then
            nextClassRef = self:GetInitRuneQuenchingClassRefByRefId(nextClass)
        end
        local nextAttrList = nextClassRef and nextClassRef.attr or {}
        if isMaxClass then
            nextAttrList = {}
        end
        local nextClassAttrList = self:GetKeyValueAttrList(nextAttrList)
        local allAttrList = self:GetKeyValueTwoAttrList(curClassAttrList, nextClassAttrList)
        list = self:GetAllAttrAddList(allAttrList, lvAttrList)
    end
    return list
end

-- 获取不能淬炼属性
function ModelRune:GetNoQuenchingAttrList(runeData)
    local list = {}
    if runeData then
        local levelAttrList = self:GetCurLevelAttrList(runeData)
        local preAttrList = self:GetCurClassAttrList(runeData)
        local allAttrList = self:GetKeyValueTwoAttrList(preAttrList, {})
        list = self:GetAllAttrAddList(allAttrList, levelAttrList)
    end
    return list
end

