function ModelRune:GetLevelAndClassAttrList(runeData, isSort)
    local list = {}
    if runeData then
        local levelAttrList = self:GetCurLevelAttrList(runeData)
        local classAttrList = self:GetCurClassAttrList(runeData)
        local curAttrKeyList = self:FormatTwoAttrListToKeyValueList(levelAttrList, classAttrList)
        if isSort then
            list = self:GetCurAttrSortList(curAttrKeyList)
        else
            list = curAttrKeyList
        end
    end
    return list
end

function ModelRune:GetAttrList(runeData)
    local list = {}
    if runeData then
        local refId = runeData.refId
        local isQuenching = self:IsCanQuenchingByRefId(refId)
        local isUpClass = self:CheckIsUpClass(runeData)
        local baseShowList = self:GetRuneUpStarAndUpLevelList(runeData, isUpClass and 2 or 1)
        local attrList = {}
        if isQuenching then
            if isUpClass then
                attrList = self:GetRuneUpClassAttrList(runeData)
            else
                attrList = self:GetRuneUpLevelAttrList(runeData)
            end
        else
            attrList = self:GetNoQuenchingAttrList(runeData)
        end
        for i, v in ipairs(baseShowList) do
            table.insert(list, v)
        end
        for i, v in ipairs(attrList) do
            table.insert(list, v)
        end
    end
    return list
end

function ModelRune:CheckIsUpClass(serverData)
    if not serverData then
        return false
    end
    local ref = GameTable.MagicRuneRef[serverData.refId]
    if not ref then
        return false
    end
    local tab = string.split(ref.mechanism, ",")
    if tab[3] ~= "1" then
        return false
    end

    local clazzRefId = serverData.clazzRefId
    local runeQuenchingClassRef = GameTable.MagicRuneQuenchingClassRef[clazzRefId]
    if not runeQuenchingClassRef then
        return false
    end
    if runeQuenchingClassRef.nextClass == -1 then
        return false
    end
    return true
end

