function ModelRune:CheckItemIsLuckOrGod(refId, itemId)
    local recastType = ModelRune.RECASTTYPE_1
    local luckItemId, godItemId = self:GetLucItemAndGodItemId(refId)
    if not luckItemId or not godItemId then
        return recastType
    end

    if luckItemId and luckItemId == itemId then
        recastType = ModelRune.RECASTTYPE_2
    elseif godItemId and godItemId == itemId then
        recastType = ModelRune.RECASTTYPE_3
    end
    return recastType
end

