function ModelRune:OnRuneListReq()
    local pb = LProtoHelper.CreateProto(LProtoIds.RuneListReq)
    SendMessage(pb, LProtoIds.RuneListReq)
end

function ModelRune:OnRuneListResp(pb, ret)
    local runeList = {}
    self._runeList = runeList
    local runes = pb.runes
    for i = 1, #runes do
        local data = runes[i]
        local id = data.id
        local rune = runeList[id]
        if not rune then
            rune = StructRune:New()
            runeList[id] = rune
        end
        rune:CreateByPb(data)
    end
end

function ModelRune:GetServerDataByPb(pb)
    local rune = StructRune:New()
    rune:CreateByPb(pb)
    return rune:GetServerData()
end

function ModelRune:OnChangeRuneReq()
    local pb = LProtoHelper.CreateProto(LProtoIds.ChangeRuneReq)
    SendMessage(pb, LProtoIds.ChangeRuneReq)
end

function ModelRune:OnChangeRuneResp(pb, ret)
    local runeList = self._runeList
    if not runeList then
        runeList = {}
        self._runeList = runeList
    end
    local changeRunes = pb.changeRunes
    for i = 1, #changeRunes do
        local changeRuneInfo = changeRunes[i]
        local syncType = changeRuneInfo.syncType
        local changeRune = changeRuneInfo.changeRune
        if syncType == 1 then
            for index, runeInfo in ipairs(changeRune) do
                local id = runeInfo.id
                local rune = StructRune:New()
                runeList[id] = rune
                rune:CreateByPb(runeInfo)
            end
        elseif syncType == 2 then
            local ids = changeRuneInfo.ids
            for index, runeId in ipairs(ids) do
                runeList[runeId] = nil
            end
        elseif syncType == 3 then
            for index, runeInfo in ipairs(changeRune) do
                local id = runeInfo.id
                local rune = StructRune:New()
                runeList[id] = rune
                rune:CreateByPb(runeInfo)
            end
        end
    end
    FireEvent(EventNames.On_Rune_Change)
end

