function ModelRune:GetRuneNameByRefIdNew(refId, limitId)
    local initRuneNameList = self._initRuneNameList
    if not initRuneNameList then
        return self:GetRuneNameByRefId(refId)
    end
    local initRuneNameInfo = initRuneNameList[refId]
    if not initRuneNameInfo then
        return self:GetRuneNameByRefId(refId)
    end
    if limitId and limitId > 0 then
        local info = initRuneNameInfo.nameOtherList
        if info then
            return info[limitId]
        end
        return self:GetRuneNameByRefId(refId)
    end
    return initRuneNameInfo.curName
end

