function ModelRune:IsEnoughUp(refId)
    local ref = self:GetSkillInfoByRefId(refId)
    if ref then
        local nextId = ref.nextId
        if nextId ~= -1 then
            local nextRef = self:GetSkillInfoByRefId(nextId)
            local enought = true
            local upItem = nextRef.upItem
            upItem = string.split(upItem, ",")
            for i, v in ipairs(upItem) do
                if not enought then
                    break
                end
                v = string.split(v, "=")
                local needRefId, needNum = tonumber(v[2]), tonumber(v[3])
                local haveNum = gModelItem:GetNumByRefId(needRefId)
                enought = haveNum >= needNum
            end
            return enought
        else
            return false
        end
    end
    return false
end

function ModelRune:GetRuneComposeRef(compoundRefId, num)
