-- isBag:背包显示的，不拷贝数据
function ModelRune:GetNotWearRuneList(isBag)
    local runeList = self._runeList
    if not runeList then
        runeList = {}
        self._runeList = runeList
    end
    local notWearRuneList = {}
    for k, v in pairs(runeList) do
        local heroId = v:GetHeroId()
        if heroId == "0" then
            if not isBag then
                local data = v:GetServerData()
                table.insert(notWearRuneList, data)
            else
                table.insert(notWearRuneList, v)
            end
        end
    end
    table.sort(notWearRuneList, function(a, b)
        local refId1, refId2 = a.refId or a._refId, b.refId or b._refId
        local qua1, qua2 = self:GetRuneQualityByRefId(refId1), self:GetRuneQualityByRefId(refId2)
        if qua1 ~= qua2 then
            return qua1 > qua2
        end
        local showStarA, showStarB = self:GetShowStarByRefId(refId1) or 0, self:GetShowStarByRefId(refId2) or 0
        if showStarA ~= showStarB then
            return showStarA > showStarB
        end
        local scoreA, scoreB = a._score or a.score, b._score or b.score
        return scoreA > scoreB
    end)
    return notWearRuneList
end

function ModelRune:GetNoWearRuneNum()
    local runeList = self._runeList
    if not runeList then
        runeList = {}
        self._runeList = runeList
    end
    local noWearNum = 0
    for k, v in pairs(runeList) do
        local heroId = v:GetHeroId()
        if heroId == "0" then
            noWearNum = noWearNum + 1
        end
    end
    return noWearNum
end

function ModelRune:GetRuneCanComposeStatus(refId)
    return self._runeCanComposeList and self._runeCanComposeList[refId] ~= nil or false
end

function ModelRune:CheckIsCanCompose(refId)
    local canComposeStatus = false
    local runeRef = self:GetRuneInfoByRefId(refId)
    if runeRef then
        local canCompose = runeRef.compose
        canComposeStatus = canCompose == 1 and self:GetRuneCanComposeStatus(refId)
    end
    return canComposeStatus
end

function ModelRune:GetCompoundRuneList(quality)
    local itemList = gModelItem:GetCompoundRuneItemList(quality)
    local canCompoundList = {}
    local notWearRuneList = self:GetNotWearRuneList()
    local func = function(limitId)
        return limitId and limitId == 0
    end
    local limitId, refId
    for i, v in ipairs(notWearRuneList) do
        refId = v.refId
        limitId = v.limitId
        if self:CheckIsCanCompose(refId) and func(limitId) then
            if quality then
                if quality == self:GetRuneQualityByRefId(refId) then
                    table.insert(canCompoundList, v)
                end
            else
                table.insert(canCompoundList, v)
            end
        end
    end
    local allList = {}
    for i, v in ipairs(itemList) do
        table.insert(allList, v)
    end
    for i, v in ipairs(canCompoundList) do
        table.insert(allList, v)
    end
    table.sort(allList, function(a, b)
        local itemTypeA, itemTypeB = a.itemType, b.itemType
        local refIdA = a.refId or a._refId
        local refIdB = b.refId or b._refId
        if itemTypeA == itemTypeB and itemTypeA == LItemTypeConst.TYPE_ITEM then
            if a.runeRefId ~= b.runeRefId then
                return refIdA < refIdB
            else
                return a.index < b.index
            end
        end
        if itemTypeA == itemTypeB and itemTypeA == LItemTypeConst.TYPE_RUNE then
            local qua1, qua2 = self:GetRuneQualityByRefId(refIdA), self:GetRuneQualityByRefId(refIdB)
            if qua1 ~= qua2 then
                return qua1 < qua2
            end
            local showStarA, showStarB = self:GetShowStarByRefId(refIdA) or 0, self:GetShowStarByRefId(refIdB) or 0
            if showStarA ~= showStarB then
                return showStarA < showStarB
            end
            local scoreA, scoreB = a._score or a.score, b._score or b.score
            return scoreA < scoreB
        end
        if itemTypeA == LItemTypeConst.TYPE_ITEM then
            refIdA = a.runeRefId
        end
        if itemTypeB == LItemTypeConst.TYPE_ITEM then
            refIdB = b.runeRefId
        end
        if itemTypeA ~= itemTypeB then
            if refIdA ~= refIdB then
                return refIdA < refIdB
            else
                return itemTypeA < itemTypeB
            end
        end
        return false
    end)
    return allList
end

---- 正常返回
function ModelRune:GetNormalRuneUpItemList(heroId, downLv, downStar)
    local runeSkillList = {}
    local runePosList = self._runePosList
    local serverData = gModelHero:GetHeroServerDataById(heroId)
    local heroAttrList, heroWearEquipList, heroWearRuneList, heroWearTalentList = gModelHero:GetHeroAttrAndEquipInfoById(heroId)
    local playerLv = gModelPlayer:GetPlayerLv()
    local lv, star = downLv or serverData.lv, downStar or serverData.star
    if not table.isempty(heroAttrList) then
        local str = ""
        --[[        if not table.isempty(heroWearRuneList) then
                    local runePosData = runePosList[1]
                    for k,v in pairs(heroWearRuneList) do
                        local limit,isInsert = runePosData[k],true
                        if limit then
                            local unlockType,demand = limit.unlockType,limit.demand
                            if unlockType == 1 then
                                isInsert = lv < demand
                            else
                                isInsert = star < demand
                            end
                        end
                        if isInsert then
                            table.insert(runeSkillList,{itype = v._type,refId = v._refId,num = 1,id = v._id})
                        end
                    end
                end]]
        if not table.isempty(heroWearTalentList) then
            local runePosData = runePosList[2]
            for k, v in pairs(heroWearTalentList) do
                local limit, isInsert = runePosData[k - 2], false
                if limit then
                    local fullNum = 0
                    local allNum = 0
                    local unlockType, demand = limit.unlockType, limit.demand
                    for idx,val in ipairs(unlockType) do
                        allNum = allNum + 1
                        local lim = demand[idx]
                        if val == 1 then
                            if lv >= lim then
                                fullNum = fullNum + 1
                            end
                        elseif val == 2 then
                            if star >= lim then
                                fullNum = fullNum + 1
                            end
                        elseif val == 3 then
                            if playerLv >= lim then
                                fullNum = fullNum + 1
                            end
                        end
                    end
                    if fullNum >= allNum then
                        isInsert = true
                    end
                end
                if isInsert then
                    local talentSkillRefId = v
                    local runeRef = self:GetSkillInfoByRefId(talentSkillRefId)
                    if runeRef then
                        local upItem = runeRef.upItem
                        if string.isempty(str) then
                            str = upItem
                        else
                            str = str .. "," .. upItem
                        end
                        local isBreak = true
                        while (isBreak) do
                            isBreak = false
                            for _k, _v in pairs(GameTable.MagicRuneSkillRef) do
                                if _v.nextId == talentSkillRefId then
                                    talentSkillRefId = _v.refId
                                    runeRef = gModelRune:GetSkillInfoByRefId(talentSkillRefId)
                                    if runeRef then
                                        upItem = runeRef.upItem
                                        if string.isempty(str) then
                                            str = upItem
                                        else
                                            str = str .. "," .. upItem
                                        end
                                    end
                                    isBreak = true
                                    break
                                end
                            end
                        end
                    end
                end
            end
            if not string.isempty(str) then
                local tempList = {}
                str = string.split(str, ",")
                for i, v in ipairs(str) do
                    v = string.split(v, "=")
                    local refId, num = tonumber(v[2]), tonumber(v[3])
                    if not tempList[refId] then
                        tempList[refId] = { refId = refId, num = 0 }
                    end
                    tempList[refId].num = tempList[refId].num + num
                end
                for k, v in pairs(tempList) do
                    table.insert(runeSkillList, { refId = v.refId, num = v.num })
                end
            end
        end
    end
    return runeSkillList
end

---- 不满足返回
function ModelRune:GetRuneUpItemList(heroId, downLv, downStar)
    local runeSkillList = {}
    local runePosList = self._runePosList
    local serverData = gModelHero:GetHeroServerDataById(heroId)
    local heroAttrList, heroWearEquipList, heroWearRuneList, heroWearTalentList = gModelHero:GetHeroAttrAndEquipInfoById(heroId)
    local playerLv = gModelPlayer:GetPlayerLv()
    local lv, star = downLv or serverData.lv, downStar or serverData.star
    if not table.isempty(heroAttrList) then
        local str = ""
        if not table.isempty(heroWearTalentList) then
            local runePosData = runePosList[2]
            for k, v in pairs(heroWearTalentList) do
                local limit, isInsert = runePosData[k - 2], false
                if limit then
                    local fullNum = 0
                    local allNum = 0
                    local unlockType, demand = limit.unlockType, limit.demand
                    for idx,val in ipairs(unlockType) do
                        allNum = allNum + 1
                        local lim = demand[idx]
                        if val == 1 then
                            if lv >= lim then
                                fullNum = fullNum + 1
                            end
                        elseif val == 2 then
                            if star >= lim then
                                fullNum = fullNum + 1
                            end
                        elseif val == 3 then
                            if playerLv >= lim then
                                fullNum = fullNum + 1
                            end
                        end
                    end
                    if fullNum < allNum then
                        isInsert = true
                    end
                end
                if isInsert then
                    local talentSkillRefId = v
                    local runeRef = self:GetSkillInfoByRefId(talentSkillRefId)
                    if runeRef then
                        local upItem = runeRef.upItem
                        if string.isempty(str) then
                            str = upItem
                        else
                            str = str .. "," .. upItem
                        end
                        local isBreak = true
                        while (isBreak) do
                            isBreak = false
                            for _k, _v in pairs(GameTable.MagicRuneSkillRef) do
                                if _v.nextId == talentSkillRefId then
                                    talentSkillRefId = _v.refId
                                    runeRef = gModelRune:GetSkillInfoByRefId(talentSkillRefId)
                                    if runeRef then
                                        upItem = runeRef.upItem
                                        if string.isempty(str) then
                                            str = upItem
                                        else
                                            str = str .. "," .. upItem
                                        end
                                    end
                                    isBreak = true
                                    break
                                end
                            end
                        end
                    end
                end
            end
            if not string.isempty(str) then
                local tempList = {}
                str = string.split(str, ",")
                for i, v in ipairs(str) do
                    v = string.split(v, "=")
                    local refId, num = tonumber(v[2]), tonumber(v[3])
                    if not tempList[refId] then
                        tempList[refId] = { refId = refId, num = 0 }
                    end
                    tempList[refId].num = tempList[refId].num + num
                end
                for k, v in pairs(tempList) do
                    table.insert(runeSkillList, { refId = v.refId, num = v.num })
                end
            end
        end
    end
    return runeSkillList
end

function ModelRune:GetRuneDataById(id)
    local runeList = self._runeList
    if not runeList then
        runeList = {}
        self._runeList = runeList
    end
    return runeList[id]
end

function ModelRune:GetRuneScore(attrList, skillList)
    local allScore = 0
    for k, v in pairs(attrList) do
        local attrRef = gModelRune:GetAttrInfoByRefId(v)
        local attr = attrRef.attr
        attr = string.split(attr, "=")
        local attrRefId, attrValue = tonumber(attr[1]), tonumber(attr[3])
        local ref = gModelHero:GetAttributeRefById(attrRefId)
        if ref then
            local powerEquip = ref.powerEquip
            local score = powerEquip * attrValue / 1000
            allScore = allScore + score
        end
    end
    for k, v in pairs(skillList) do
        local skillRef = self:GetSkillInfoByRefId(v)
        if skillRef then
            local score = skillRef.score
            allScore = allScore + score
        else
            if LOG_INFO_ENABLED then
                printInfoNR("=============================== 打印而已，莫慌：没有找到对应的技能:" .. v)
            end
        end
    end
    return allScore
end

function ModelRune:_GetRuneKeys(list)
    if #list < 1 then return {} end
    local keyList = {}
    local itemType, runeRefId
    for i, v in ipairs(list) do
        itemType = v.itemType
        if itemType == LItemTypeConst.TYPE_ITEM then
            runeRefId = v.runeRefId
        elseif itemType == LItemTypeConst.TYPE_RUNE then
            runeRefId = v.refId
        end
        local num = keyList[runeRefId] or 0
        num = num + 1
        keyList[v.refId] = num
    end
    return keyList
end

function ModelRune:GetCompoundRuneNum()
    local list = self:GetCompoundRuneList()
    local compoundNum = ModelRune.RP_COMPOUND_NUM
    local keyList = self:_GetRuneKeys(list)
    for tRuneRefId, canCompoundNum in pairs(keyList) do
        if canCompoundNum >= compoundNum then
            if self:CheckCompoundNeedEnough(tRuneRefId,compoundNum) then
                return true
            end
        end
    end
    return false
end

function ModelRune:CheckRuneCompoundRPByQuality(quality)
    local list = self:GetCompoundRuneList(quality)
    if #list < 1 then return false end
    local compoundNum = ModelRune.RP_COMPOUND_NUM
    local keyList = self:_GetRuneKeys(list)
    for tRuneRefId, canCompoundNum in pairs(keyList) do
        if canCompoundNum >= compoundNum then
            if self:CheckCompoundNeedEnough(tRuneRefId,compoundNum) then
                return true
            end
        end
    end
    return false
end

function ModelRune:CheckCompoundNeedEnough(runeRefId,compoundNum)
    compoundNum = compoundNum or ModelRune.RP_COMPOUND_NUM
    local ref = self:GetRuneComposeInfoByCompoundRefIdAndComnpoundNum(runeRefId, compoundNum)
    if ref then
        if gModelFunctionOpen:CheckIsOpened(ref.needLevel) then
            local composeNeedGlod = ref.composeNeedGlod
            local itemNum = composeNeedGlod.itemNum
            local num = gModelItem:GetNumByRefId(composeNeedGlod.itemId)
            if num >= itemNum then
                return true
            end
        end
    end
    return false
end

function ModelRune:GetHaveNumOrNeedNum()
    local meltingNeed = self:GetConfig("meltingNeed")
    local str = string.split(meltingNeed, "=")
    local needRefId, needNum = tonumber(str[2]), tonumber(str[3])
    local haveNum = gModelItem:GetNumByRefId(needRefId)
    return haveNum, needNum
end

function ModelRune:GetBMeltingRed()
    local haveNum, needNum = self:GetHaveNumOrNeedNum()
    return haveNum >= needNum
end

function ModelRune:GetClearNewList()
    local list = {}
    for k, v in pairs(self._runeList) do
        local serverData = v:GetServerData()
        if serverData then
            local state = serverData.state
            if state == ModelItem.ITEM_NEW_STATUS then
                table.insert(list, {
                    refId = serverData.refId,
                    id = serverData.id
                })
            end
        end
    end
    return list
end

function ModelRune:SortRuneList(list)
    list = list or {}
    table.sort(list, function(a, b)
        local refIdA, refIdB = a.refId, b.refId
        local qualityA, qualityB = self:GetRuneQualityByRefId(refIdA), self:GetRuneQualityByRefId(refIdB)
        if qualityA ~= qualityB then
            return qualityA > qualityB
        end
        local scoreA, scoreB = a.score, b.score
        if scoreA ~= scoreB then
            return scoreA > scoreB
        end
        local clazzRefIdA, clazzRefIdB = a.clazzRefId, b.clazzRefId
        local runeClassA, runeClassB = self:GetRuneClassByClassRefId(clazzRefIdA),
            self:GetRuneClassByClassRefId(clazzRefIdB)
        if runeClassA ~= runeClassB then
            return runeClassA > runeClassB
        end
        return a.id > b.id
    end)
    return list
end

-- status:1为穿戴，2为背包中
function ModelRune:GetSMVRuneListByRuneRefIdAndStatus(needRuneRefId, status, curRuneData, page)
    local runeList = self._runeList
    if not runeList then
        runeList = {}
        self._runeList = runeList
    end
    curRuneData = curRuneData or {}
    local curRuneId = curRuneData.id
    page = page or ModelRune.TYPE_SKILLRECAST

    local itemList = {}
    if status == 2 then
        local runeUseItemList = gModelItem:GetRuneUseItemList(needRuneRefId)
        local refId
        for i, v in ipairs(runeUseItemList) do
            refId = v.refId
            for idx = 1, v.num do
                table.insert(itemList, {
                    refId = refId,
                    num = 1,
                    itemType = v.itype,
                    id = refId .. "_" .. idx,
                })
            end
        end
    end
    local canSelRuneList = {}
    for id, runeInfo in pairs(runeList) do
        local refId = runeInfo._refId
        if needRuneRefId and needRuneRefId == refId and curRuneId and curRuneId ~= runeInfo._id then
            local ins = false
            if runeInfo.limitId and runeInfo.limitId <= 0 then
                if status == 1 then
                    --ins = runeInfo._heroId ~= "0" and self:CheckIsMechanismOpen(refId,page)
                    ins = runeInfo._heroId ~= "0"
                elseif status == 2 then
                    --ins = runeInfo._heroId == "0" and self:CheckIsMechanismOpen(refId,page)
                    ins = runeInfo._heroId == "0"
                end
            end
            if ins then
                table.insert(canSelRuneList, runeInfo:GetServerData())
            end
        end
    end
    canSelRuneList = self:SortRuneList(canSelRuneList)

    local list = {}
    for i, v in ipairs(itemList) do
        table.insert(list, v)
    end
    for i, v in ipairs(canSelRuneList) do
        table.insert(list, v)
    end

    return list
end

function ModelRune:GetRSVRuneListByRuneRefIdAndStatus(status, curRuneData, page)
    curRuneData = curRuneData or {}
    local curRuneId = curRuneData.id
    local runeList = self._runeList
    if not runeList then
        runeList = {}
        self._runeList = runeList
    end
    page = page or ModelRune.TYPE_SKILLRECAST
    local list = {}
    for id, runeInfo in pairs(runeList) do
        local ins = curRuneId and curRuneId ~= runeInfo._id
        if ins then
            if status == 1 then
                ins = runeInfo._heroId ~= "0" and self:CheckIsMechanismOpen(runeInfo._refId, page)
            elseif status == 2 then
                ins = runeInfo._heroId == "0" and self:CheckIsMechanismOpen(runeInfo._refId, page)
            end
        end
        if ins then
            table.insert(list, runeInfo:GetServerData())
        end
    end
    list = self:SortRuneList(list)
    return list
end

