function ModelRune:OpenNewRuneSkillWnd(refId, skillType)
    local list = {}
    local skillTypeList = self:GetSkillTypeListBySkillType(skillType) or {}
    local target
    for i, v in ipairs(skillTypeList) do
        if not target then
            table.insert(list, v.refId)
        end
        if target == -1 then
            break
        end
        target = v.nextId
        table.insert(list, target)
    end

    local skillList = {}
    for i, v in ipairs(list) do
        local ref = self:GetSkillInfoByRefId(v)
        if ref then
            table.insert(skillList, ref.SkillId)
        end
    end
    local curSkillId
    local ref = self:GetSkillInfoByRefId(refId)
    if ref then
        curSkillId = ref.SkillId
    end
    --GF.OpenWndTop("UINewJNTip",{skillList = skillList,curSkillId = curSkillId,wndType = 3})
    gModelGeneral:OpenSkillWnd({ skillList = skillList, curSkillId = curSkillId, wndType = 3 })
end

function ModelRune:GetRuneDecomposeItemListByRuneData(runeData)
    local list = {}
    if runeData then
        local payItemList = {}
        local levelRefId = runeData.levelRefId
        local refData = self:GetRuneQuenchingRefByRefId(levelRefId)
        if refData then
            local returnUpItem = refData.returnUpItem or {}
            for i, v in ipairs(returnUpItem) do
                local itemType, itemId, itemNum = v.itemType, v.itemId, v.itemNum
                local payItemTypeList = payItemList[itemType]
                if not payItemTypeList then
                    payItemTypeList = {}
                    payItemList[itemType] = payItemTypeList
                end
                local itemIdNum = payItemTypeList[itemId] or 0
                payItemTypeList[itemId] = itemIdNum + itemNum
            end
        end

        local decompose = self:GetRuneDecomposeItemListByRefId(runeData.refId) or {}
        for i, v in ipairs(decompose) do
            local itemType, itemId, itemNum = v.itemType, v.itemId, v.itemNum
            local payItemTypeList = payItemList[itemType]
            if not payItemTypeList then
                payItemTypeList = {}
                payItemList[itemType] = payItemTypeList
            end
            local itemIdNum = payItemTypeList[itemId] or 0
            payItemTypeList[itemId] = itemIdNum + itemNum
        end

        for itemType, itemIdList in pairs(payItemList) do
            for itemId, itemNum in pairs(itemIdList) do
                table.insert(list, {
                    itemType = itemType,
                    itemId = itemId,
                    itemNum = itemNum,
                })
            end
        end
        table.sort(list, function(a, b)
            local orderA = gModelItem:GetItemOrderByRefId(a.itemId)
            local orderB = gModelItem:GetItemOrderByRefId(b.itemId)
            return orderA < orderB
        end)
    end
    return list
end

